// src/reads/vault.ts
async function getVaultState(publicClient, vaultAddress) {
  const [name, symbol, decimals, totalSupply, totalAssets, asset] = await Promise.all([
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: "name"
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: "symbol"
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: "decimals"
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: "totalSupply"
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: "totalAssets"
    }),
    publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: "asset"
    })
  ]);
  const assetDecimals = await publicClient.readContract({
    address: asset,
    abi: erc20Abi,
    functionName: "decimals"
  });
  const exchangeRate = totalSupply > 0n ? await publicClient.readContract({
    address: vaultAddress,
    abi: erc4626Abi,
    functionName: "convertToAssets",
    args: [10n ** BigInt(decimals)]
  }) : 10n ** BigInt(assetDecimals);
  return {
    address: vaultAddress,
    name,
    symbol,
    decimals,
    totalAssets,
    totalSupply,
    asset,
    assetDecimals,
    exchangeRate
  };
}
