var MAX_UINT256 = 2n ** 256n - 1n;
async function getTokenAllowance(publicClient, token, owner, spender) {
  if (isNativeToken(token)) {
    console.log("[getTokenAllowance] native token detected \u2014 returning MAX_UINT256");
    return { token, owner, spender, allowance: MAX_UINT256 };
  }
  const allowance = await publicClient.readContract({
    address: token,
    abi: erc20Abi,
    functionName: "allowance",
    args: [owner, spender]
  });
  return {
    token,
    owner,
    spender,
    allowance
  };
}
async function hasEnoughAllowance(publicClient, token, owner, spender, amount) {
  const { allowance } = await getTokenAllowance(publicClient, token, owner, spender);
  return allowance >= amount;
}

